changeSet.sql:
DO $body$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'estado_pedido') THEN
        CREATE TYPE estado_pedido AS ENUM ('CREADO','CONFIRMADO','PAGADO','CANCELADO');
    END IF;
END $body$;

CREATE INDEX IF NOT EXISTS idx_pedido_estado     ON pedido(estado);
CREATE INDEX IF NOT EXISTS idx_pedido_cliente_id ON pedido(cliente_id);
CREATE INDEX IF NOT EXISTS idx_pedido_fecha      ON pedido(fecha DESC);

changeSet.rollback:
DROP INDEX IF EXISTS idx_pedido_estado;
DROP INDEX IF EXISTS idx_pedido_cliente_id;
DROP INDEX IF EXISTS idx_pedido_fecha;
